INSERT INTO Introductions (DoctorId, SectionId, Content) VALUES
(1, 1, N'Dr. Stephen Strange is a board-certified neurosurgeon known for precise microsurgical technique and strong clinical judgment. He focuses on complex brain and spinal procedures and combines surgical skill with evidence-based patient care.'),
(1, 2, N'Dr. Stephen Strange, MD
Columbia University College of Physicians and Surgeons, USA
Harvard Medical School Advanced Fellowship in Complex Brain Surgery
Board Certification in Neurosurgery'),
(1, 3, N'2008 - Present: Senior Neurosurgeon, Metro General Hospital, USA
2004 - 2008: Neurosurgical Fellow, Harvard Medical School Hospitals, USA
2000 - 2004: Neurosurgery Resident, Columbia University Medical Center, USA'),
(1, 4, N'2018: International Excellence in Neurosurgery Award
2015: American Neurological Association Research Recognition'),

(2, 1, N'Dr. Victor Frankenstein is an expert in regenerative medicine and experimental surgery with a strong research profile bridging laboratory innovation and clinical application. He leads translational projects that aim to improve reconstruction outcomes and tissue regeneration techniques.'),
(2, 2, N'Victor Frankenstein, MD, PhD
University of Geneva Faculty of Medicine, Switzerland
PhD in Biomedical Engineering
Advanced Research Fellowship in Regenerative Medicine, Germany'),
(2, 3, N'2006 - Present: Lead Research Surgeon, Geneva Medical Research Institute, Switzerland
2001 - 2006: Senior Surgical Researcher, Heidelberg Medical Center, Germany
1998 - 2001: Clinical Fellow, University Hospital Geneva, Switzerland'),
(2, 4, N'2016: European Medical Innovation Prize'),

(3, 1, N'Dr. Hana Lee is a caring internal medicine physician focused on preventive care and long-term chronic disease management. She emphasizes patient education, lifestyle interventions, and evidence-based treatment plans to support sustained health.'),
